import React, { useState, useEffect } from 'react';
import { Order, OrderStatus, Measurements, Customer } from '../types';
import { storage } from '../services/storage';
import AbayaDiagram from './AbayaDiagram';
import { Save, Printer, ArrowRight, UserPlus, Search } from 'lucide-react';

interface OrderFormProps {
  initialOrder?: Order;
  onComplete: () => void;
  onPrint: (order: Order) => void;
}

const OrderForm: React.FC<OrderFormProps> = ({ initialOrder, onComplete, onPrint }) => {
  const [order, setOrder] = useState<Partial<Order>>(initialOrder || {
    id: crypto.randomUUID(),
    orderNo: `INV-${Date.now().toString().slice(-6)}`,
    date: new Date().toISOString().split('T')[0],
    customerName: '',
    customerPhone: '',
    customerAddress: '',
    abayaNo: '',
    designName: '',
    color: '',
    fabric: '',
    notes: '',
    measurements: {
      sleeveFromNeck: '',
      arms: '',
      bust: '',
      sleeveWidth: '',
      waist: '',
      abayaLength: ''
    },
    totalAmount: 0,
    paidAmount: 0,
    remainingAmount: 0,
    discount: 0,
    shipping: 0,
    status: OrderStatus.IN_PROGRESS,
    createdAt: Date.now()
  });

  const [customerSearch, setCustomerSearch] = useState('');
  const [showCustomerSearch, setShowCustomerSearch] = useState(false);
  const customers = storage.getCustomers();

  useEffect(() => {
    const total = Number(order.totalAmount || 0);
    const discount = Number(order.discount || 0);
    const shipping = Number(order.shipping || 0);
    const paid = Number(order.paidAmount || 0);
    const finalTotal = total - discount + shipping;
    setOrder(prev => ({
      ...prev,
      remainingAmount: Math.max(0, finalTotal - paid)
    }));
  }, [order.totalAmount, order.paidAmount, order.discount, order.shipping]);

  const handleSave = () => {
    if (!order.customerName || !order.customerPhone) {
      alert('يرجى إدخال اسم العميل ورقمه');
      return;
    }
    const finalOrder = order as Order;
    storage.saveOrder(finalOrder);
    storage.updateCustomerFromOrder(finalOrder);
    onComplete();
  };

  const handleMeasurementChange = (key: keyof Measurements, value: string) => {
    setOrder(prev => ({
      ...prev,
      measurements: {
        ...prev.measurements!,
        [key]: value
      }
    }));
  };

  const selectCustomer = (c: Customer) => {
    setOrder(prev => ({
      ...prev,
      customerName: c.name,
      customerPhone: c.phone,
      customerAddress: c.address,
      measurements: c.lastMeasurements || prev.measurements
    }));
    setShowCustomerSearch(false);
  };

  return (
    <div className="pb-20">
      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center gap-4">
          <button onClick={onComplete} className="p-2 hover:bg-pink-100 rounded-full text-pink-600 transition-colors">
            <ArrowRight size={24} />
          </button>
          <h2 className="text-2xl font-bold text-gray-800">
            {initialOrder ? 'تعديل فاتورة' : 'إنشاء فاتورة جديدة'}
          </h2>
        </div>
        <div className="flex gap-2">
          <button
            onClick={() => onPrint(order as Order)}
            className="flex items-center gap-2 px-6 py-2 bg-white border border-pink-200 text-pink-600 rounded-xl hover:bg-pink-50 transition-all font-medium"
          >
            <Printer size={18} />
            <span>معاينة للطباعة</span>
          </button>
          <button
            onClick={handleSave}
            className="flex items-center gap-2 px-8 py-2 bg-pink-600 text-white rounded-xl hover:bg-pink-700 shadow-md shadow-pink-100 transition-all font-medium"
          >
            <Save size={18} />
            <span>حفظ الطلب</span>
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Customer & Order Details */}
        <div className="lg:col-span-2 space-y-8">
          <section className="bg-white rounded-3xl p-8 border border-pink-50 shadow-sm relative overflow-hidden">
            <div className="absolute top-0 left-0 w-2 h-full bg-pink-500"></div>
            <div className="flex items-center justify-between mb-6">
              <h3 className="text-lg font-bold text-gray-800 flex items-center gap-2">
                <UserPlus size={20} className="text-pink-500" />
                بيانات العميل
              </h3>
              <div className="relative">
                <button 
                  onClick={() => setShowCustomerSearch(!showCustomerSearch)}
                  className="text-sm text-pink-600 hover:underline flex items-center gap-1"
                >
                  <Search size={14} />
                  بحث عن عميل سابق
                </button>
                {showCustomerSearch && (
                  <div className="absolute top-full left-0 mt-2 w-64 bg-white border border-pink-100 rounded-2xl shadow-xl z-10 overflow-hidden">
                    <input 
                      autoFocus
                      className="w-full p-3 border-b text-sm focus:outline-none"
                      placeholder="ابحث بالاسم أو الرقم..."
                      onChange={(e) => setCustomerSearch(e.target.value)}
                    />
                    <div className="max-h-48 overflow-y-auto">
                      {customers.filter(c => c.name.includes(customerSearch) || c.phone.includes(customerSearch)).map(c => (
                        <button 
                          key={c.id}
                          className="w-full text-right p-3 hover:bg-pink-50 text-sm border-b border-pink-50"
                          onClick={() => selectCustomer(c)}
                        >
                          <div className="font-bold">{c.name}</div>
                          <div className="text-xs text-gray-400">{c.phone}</div>
                        </button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-2">الاسم</label>
                <input
                  type="text"
                  value={order.customerName}
                  onChange={(e) => setOrder({...order, customerName: e.target.value})}
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-pink-200 focus:outline-none transition-all"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-2">الرقم</label>
                <input
                  type="tel"
                  value={order.customerPhone}
                  onChange={(e) => setOrder({...order, customerPhone: e.target.value})}
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-pink-200 focus:outline-none transition-all"
                />
              </div>
              <div className="md:col-span-2">
                <label className="block text-sm font-medium text-gray-600 mb-2">العنوان</label>
                <input
                  type="text"
                  value={order.customerAddress}
                  onChange={(e) => setOrder({...order, customerAddress: e.target.value})}
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-pink-200 focus:outline-none transition-all"
                />
              </div>
            </div>
          </section>

          <section className="bg-white rounded-3xl p-8 border border-pink-50 shadow-sm">
            <h3 className="text-lg font-bold text-gray-800 mb-6">تفاصيل العباية</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-2">رقم العباية</label>
                <input
                  type="text"
                  value={order.abayaNo}
                  onChange={(e) => setOrder({...order, abayaNo: e.target.value})}
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-pink-200 focus:outline-none transition-all"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-2">اسم التصميم</label>
                <input
                  type="text"
                  value={order.designName}
                  onChange={(e) => setOrder({...order, designName: e.target.value})}
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-pink-200 focus:outline-none transition-all"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-2">اللون</label>
                <input
                  type="text"
                  value={order.color}
                  onChange={(e) => setOrder({...order, color: e.target.value})}
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-pink-200 focus:outline-none transition-all"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-2">القماش</label>
                <input
                  type="text"
                  value={order.fabric}
                  onChange={(e) => setOrder({...order, fabric: e.target.value})}
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-pink-200 focus:outline-none transition-all"
                />
              </div>
              <div className="md:col-span-2">
                <label className="block text-sm font-medium text-gray-600 mb-2">ملاحظات إضافية</label>
                <textarea
                  rows={3}
                  value={order.notes}
                  onChange={(e) => setOrder({...order, notes: e.target.value})}
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-pink-200 focus:outline-none transition-all"
                />
              </div>
            </div>
          </section>
        </div>

        {/* Measurements & Totals */}
        <div className="space-y-8">
          <AbayaDiagram 
            measurements={order.measurements as Measurements} 
            onChange={handleMeasurementChange} 
          />

          <section className="bg-white rounded-3xl p-8 border border-pink-50 shadow-sm">
            <h3 className="text-lg font-bold text-gray-800 mb-6">الحساب والدفع</h3>
            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <span className="text-gray-500">الإجمالي</span>
                <input
                  type="number"
                  value={order.totalAmount}
                  onChange={(e) => setOrder({...order, totalAmount: Number(e.target.value)})}
                  className="w-24 px-2 py-1 bg-gray-50 border border-gray-100 rounded text-left focus:outline-none"
                />
              </div>
              <div className="flex justify-between items-center">
                <span className="text-gray-500">الخصم</span>
                <input
                  type="number"
                  value={order.discount}
                  onChange={(e) => setOrder({...order, discount: Number(e.target.value)})}
                  className="w-24 px-2 py-1 bg-gray-50 border border-gray-100 rounded text-left focus:outline-none"
                />
              </div>
              <div className="flex justify-between items-center">
                <span className="text-gray-500">الشحن</span>
                <input
                  type="number"
                  value={order.shipping}
                  onChange={(e) => setOrder({...order, shipping: Number(e.target.value)})}
                  className="w-24 px-2 py-1 bg-gray-50 border border-gray-100 rounded text-left focus:outline-none"
                />
              </div>
              <div className="border-t border-dashed border-pink-100 my-4 pt-4 flex justify-between items-center font-bold text-pink-700">
                <span>المبلغ الكلي</span>
                <span>{(Number(order.totalAmount || 0) - Number(order.discount || 0) + Number(order.shipping || 0)).toLocaleString()} ر.س</span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-gray-500">المبلغ المدفوع (العربون)</span>
                <input
                  type="number"
                  value={order.paidAmount}
                  onChange={(e) => setOrder({...order, paidAmount: Number(e.target.value)})}
                  className="w-24 px-2 py-1 bg-green-50 border border-green-100 rounded text-left font-bold text-green-700 focus:outline-none"
                />
              </div>
              <div className="flex justify-between items-center text-red-600 font-bold bg-red-50 p-3 rounded-xl mt-4">
                <span>المتبقي</span>
                <span>{order.remainingAmount?.toLocaleString()} ر.س</span>
              </div>
            </div>
          </section>

          <section className="bg-white rounded-3xl p-8 border border-pink-50 shadow-sm">
            <h3 className="text-lg font-bold text-gray-800 mb-6">حالة الطلب</h3>
            <div className="grid grid-cols-2 gap-2">
              {Object.values(OrderStatus).map((status) => (
                <button
                  key={status}
                  onClick={() => setOrder({...order, status})}
                  className={`px-4 py-2 rounded-xl text-xs font-medium transition-all ${
                    order.status === status 
                      ? 'bg-pink-600 text-white shadow-md' 
                      : 'bg-pink-50 text-pink-700 hover:bg-pink-100'
                  }`}
                >
                  {status}
                </button>
              ))}
            </div>
          </section>
        </div>
      </div>
    </div>
  );
};

export default OrderForm;

import React from 'react';
import { storage } from '../services/storage';
import { OrderStatus } from '../types';
import { 
  TrendingUp, 
  ShoppingBag, 
  Users as UsersIcon, 
  Clock,
  CheckCircle2,
  Package,
  Truck
} from 'lucide-react';

const Dashboard: React.FC = () => {
  const orders = storage.getOrders();
  const customers = storage.getCustomers();

  const stats = {
    totalSales: orders.reduce((acc, o) => acc + (o.totalAmount - o.discount + o.shipping), 0),
    totalOrders: orders.length,
    activeCustomers: customers.length,
    inProgress: orders.filter(o => o.status === OrderStatus.IN_PROGRESS).length,
    ready: orders.filter(o => o.status === OrderStatus.READY).length,
    shipped: orders.filter(o => o.status === OrderStatus.SHIPPED).length,
    delivered: orders.filter(o => o.status === OrderStatus.DELIVERED).length,
  };

  const cards = [
    { label: 'إجمالي المبيعات', value: `${stats.totalSales.toLocaleString()} ر.س`, icon: TrendingUp, color: 'text-green-600', bg: 'bg-green-50' },
    { label: 'عدد الطلبات', value: stats.totalOrders, icon: ShoppingBag, color: 'text-pink-600', bg: 'bg-pink-50' },
    { label: 'إجمالي العملاء', value: stats.activeCustomers, icon: UsersIcon, color: 'text-purple-600', bg: 'bg-purple-50' },
  ];

  const statusItems = [
    { label: 'قيد التنفيذ', value: stats.inProgress, icon: Clock, color: 'text-amber-500' },
    { label: 'جاهز للاستلام', value: stats.ready, icon: CheckCircle2, color: 'text-blue-500' },
    { label: 'تم الشحن', value: stats.shipped, icon: Truck, color: 'text-indigo-500' },
    { label: 'تم التسليم', value: stats.delivered, icon: Package, color: 'text-emerald-500' },
  ];

  return (
    <div className="space-y-8">
