import React, { useState, useEffect } from 'react';
import { Order, OrderStatus, Measurements, Customer } from '../types';
import { storage } from '../services/storage';
import AbayaDiagram from './AbayaDiagram';
import { Save, Printer, ArrowRight, UserPlus, Search } from 'lucide-react';

interface OrderFormProps {
  initialOrder?: Order;
  onComplete: () => void;
  onPrint: (order: Order) => void;
}

const OrderForm: React.FC<OrderFormProps> = ({ initialOrder, onComplete, onPrint }) => {
  const [order, setOrder] = useState<Partial<Order>>(initialOrder || {
    id: crypto.randomUUID(),
    orderNo: `INV-${Date.now().toString().slice(-6)}`,
    date: new Date().toISOString().split('T')[0],
    customerName: '',
    customerPhone: '',
    customerAddress: '',
    abayaNo: '',
    designName: '',
    color: '',
    fabric: '',
    notes: '',
    measurements: {
      sleeveFromNeck: '',
      arms: '',
      bust: '',
      sleeveWidth: '',
      waist: '',
      abayaLength: ''
    },
    totalAmount: 0,
    paidAmount: 0,
    remainingAmount: 0,
    discount: 0,
    shipping: 0,
    status: OrderStatus.IN_PROGRESS,
    createdAt: Date.now()
  });

  const [customerSearch, setCustomerSearch] = useState('');
  const [showCustomerSearch, setShowCustomerSearch] = useState(false);
  const customers = storage.getCustomers();

  useEffect(() => {
    const total = Number(order.totalAmount || 0);
    const discount = Number(order.discount || 0);
    const shipping = Number(order.shipping || 0);
    const paid = Number(order.paidAmount || 0);
    const finalTotal = total - discount + shipping;
    setOrder(prev => ({
      ...prev,
      remainingAmount: Math.max(0, finalTotal - paid)
    }));
  }, [order.totalAmount, order.paidAmount, order.discount, order.shipping]);

  const handleSave = () => {
    if (!order.customerName || !order.customerPhone) {
      alert('يرجى إدخال اسم العميل ورقمه');
      return;
    }
    const finalOrder = order as Order;
    storage.saveOrder(finalOrder);
    storage.updateCustomerFromOrder(finalOrder);
    onComplete();
  };

  const handleMeasurementChange = (key: keyof Measurements, value: string) => {
    setOrder(prev => ({
      ...prev,
      measurements: {
        ...prev.measurements!,
        [key]: value
      }
    }));
  };

  const selectCustomer = (c: Customer) => {
    setOrder(prev => ({
      ...prev,
      customerName: c.name,
      customerPhone: c.phone,
      customerAddress: c.address,
      measurements: c.lastMeasurements || prev.measurements
    }));
    setShowCustomerSearch(false);
  };

  return (
    <div className="pb-20">
      <div className="flex items-center justify-between mb-8">
        <div className="flex items-center gap-4">
          <button onClick={onComplete} className="p-2 hover:bg-pink-100 rounded-full text-pink-600 transition-colors">
            <ArrowRight size={24} />
          </button>
          <h2 className="text-2xl font-bold text-gray-800">
            {initialOrder ? 'تعديل فاتورة' : 'إنشاء فاتورة جديدة'}
          </h2>
        </div>
        <div className="flex gap-2">
          <button
            onClick={() => onPrint(order as Order)}
            className="flex items-center gap-2 px-6 py-2 bg-white border border-pink-200 text-pink-600 rounded-xl hover:bg-pink-50 transition-all font-medium"
          >
            <Printer size={18} />
            <span>معاينة للطباعة</span>
          </button>
          <button
            onClick={handleSave}
            className="flex items-center gap-2 px-8 py-2 bg-pink-600 text-white rounded-xl hover:bg-pink-700 shadow-md shadow-pink-100 transition-all font-medium"
          >
            <Save size={18} />
            <span>حفظ الطلب</span>
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Customer & Order Details */}
        <div className="lg:col-span-2 space-y-8">
          <section className="bg-white rounded-3xl p-8 border border-pink-50 shadow-sm relative overflow-hidden">
            <div className="absolute top-0 left-0 w-2 h-full bg-pink-500"></div>
            <div className="flex items-center justify-between mb-6">
              <h3 className="text-lg font-bold text-gray-800 flex items-center gap-2">
                <UserPlus size={20} className="text-pink-500" />
                بيانات العميل
              </h3>
              <div className="relative">
                <button 
                  onClick={() => setShowCustomerSearch(!showCustomerSearch)}
                  className="text-sm text-pink-600 hover:underline flex items-center gap-1"
                >
                  <Search size={14} />
                  بحث عن عميل سابق
                </button>
                {showCustomerSearch && (
                  <div className="absolute top-full left-0 mt-2 w-64 bg-white border border-pink-100 rounded-2xl shadow-xl z-10 overflow-hidden">
                    <input 
                      autoFocus
                      className="w-full p-3 border-b text-sm focus:outline-none"
                      placeholder="ابحث بالاسم أو الرقم..."
                      onChange={(e) => setCustomerSearch(e.target.value)}
                    />
                    <div className="max-h-48 overflow-y-auto">
                      {customers.filter(c => c.name.includes(customerSearch) || c.phone.includes(customerSearch)).map(c => (
                        <button 
                          key={c.id}
                          className="w-full text-right p-3 hover:bg-pink-50 text-sm border-b border-pink-50"
                          onClick={() => selectCustomer(c)}
                        >
                          <div className="font-bold">{c.name}</div>
                          <div className="text-xs text-gray-400">{c.phone}</div>
                        </button>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-2">الاسم</label>
                <input
                  type="text"
                  value={order.customerName}
                  onChange={(e) => setOrder({...order, customerName: e.target.value})}
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-pink-200 focus:outline-none transition-all"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-2">الرقم</label>
                <input
                  type="tel"
                  value={order.customerPhone}
                  onChange={(e) => setOrder({...order, customerPhone: e.target.value})}
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-pink-200 focus:outline-none transition-all"
                />
              </div>
              <div className="md:col-span-2">
                <label className="block text-sm font-medium text-gray-600 mb-2">العنوان</label>
                <input
                  type="text"
                  value={order.customerAddress}
                  onChange={(e) => setOrder({...order, customerAddress: e.target.value})}
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-pink-200 focus:outline-none transition-all"
                />
              </div>
            </div>
          </section>

          <section className="bg-white rounded-3xl p-8 border border-pink-50 shadow-sm">
            <h3 className="text-lg font-bold text-gray-800 mb-6">تفاصيل العباية</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-2">رقم العباية</label>
                <input
                  type="text"
                  value={order.abayaNo}
                  onChange={(e) => setOrder({...order, abayaNo: e.target.value})}
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-pink-200 focus:outline-none transition-all"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-2">اسم التصميم</label>
                <input
                  type="text"
                  value={order.designName}
                  onChange={(e) => setOrder({...order, designName: e.target.value})}
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-pink-200 focus:outline-none transition-all"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-2">اللون</label>
                <input
                  type="text"
                  value={order.color}
                  onChange={(e) => setOrder({...order, color: e.target.value})}
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-pink-200 focus:outline-none transition-all"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-600 mb-2">القماش</label>
                <input
                  type="text"
                  value={order.fabric}
                  onChange={(e) => setOrder({...order, fabric: e.target.value})}
