              <div className="flex justify-between items-center">
                <span className="text-gray-500 text-sm">الشحن</span>
                <input
                  type="text"
                  inputMode="decimal"
                  value={shippingStr}
                  onChange={(e) => setShippingStr(e.target.value)}
                  className="w-24 px-2 py-1 bg-gray-50 border border-gray-100 rounded text-center focus:outline-none focus:ring-1 focus:ring-pink-200"
                />
