import React from 'react';
import { Order, OrderStatus } from '../types';
import { CheckCircle2, Clock, Truck, Package, ArrowRight, ShieldCheck } from 'lucide-react';

interface TrackingViewProps {
  order: Order;
  onBack?: () => void;
}

const TrackingView: React.FC<TrackingViewProps> = ({ order, onBack }) => {
  const statusSteps = [
    { status: OrderStatus.IN_PROGRESS, icon: Clock, label: 'بدأنا التفصيل' },
    { status: OrderStatus.READY, icon: CheckCircle2, label: 'طلبك جاهز' },
    { status: OrderStatus.SHIPPED, icon: Truck, label: 'في الطريق إليك' },
    { status: OrderStatus.DELIVERED, icon: Package, label: 'تم التسليم' },
  ];

  const currentIndex = statusSteps.findIndex(s => s.status === order.status);

  return (
    <div className="min-h-screen bg-gray-50/30 p-6 flex flex-col items-center">
      <div className="w-full max-w-md space-y-8 mt-6">
        <div className="text-center space-y-2">
          <h1 className="text-4xl font-bold text-pink-800" style={{ fontFamily: 'serif' }}>CUTE BASE</h1>
          <p className="text-pink-400 tracking-[0.3em] text-sm">تتبع طلبك — TRACK ORDER</p>
        </div>

        <div className="bg-amber-50 border border-amber-100 p-3 rounded-2xl flex items-center justify-center gap-2 text-[10px] text-amber-700 font-bold">
          <ShieldCheck size={14} />
          هذه الصفحة للمعاينة فقط - لا يمكن تعديل البيانات من هنا
        </div>

        <div className="bg-white rounded-[2.5rem] p-8 border border-pink-100 shadow-xl shadow-pink-100/20 space-y-6 text-center">
          <div>
            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mb-1">مرحباً بكِ أ.</p>
            <h2 className="text-2xl font-bold text-gray-800">{order.customerName}</h2>
          </div>
          <div className="flex flex-col gap-2">
             <div className="inline-block px-4 py-2 bg-pink-50 rounded-2xl border border-pink-100">
              <p className="text-xs text-pink-600 font-bold">رقم الطلب: {order.orderNo}</p>
            </div>
            <p className="text-[10px] text-gray-400">تاريخ الطلب: {order.date}</p>
          </div>
        </div>

        {/* Stepper */}
        <div className="bg-white rounded-[2.5rem] p-8 border border-pink-50 shadow-sm space-y-8">
          <h3 className="text-sm font-bold text-gray-400 border-b border-gray-50 pb-4">حالة الطلب الحالية</h3>
          <div className="relative space-y-8 px-2">
            {statusSteps.map((step, index) => {
              const Icon = step.icon;
              const isCompleted = index <= currentIndex;
              const isLast = index === statusSteps.length - 1;

              return (
                <div key={index} className="flex items-start gap-6 relative">
                  {!isLast && (
                    <div className={`absolute right-[21px] top-10 w-0.5 h-10 ${isCompleted && index < currentIndex ? 'bg-pink-500' : 'bg-gray-100'}`} />
                  )}
                  <div className={`z-10 w-11 h-11 rounded-2xl flex items-center justify-center transition-all duration-500 ${isCompleted ? 'bg-pink-600 text-white shadow-lg shadow-pink-200' : 'bg-gray-100 text-gray-300'}`}>
                    <Icon size={22} />
                  </div>
                  <div className="pt-1">
                    <p className={`font-bold ${isCompleted ? 'text-gray-800' : 'text-gray-300'}`}>{step.label}</p>
                    <p className="text-[10px] text-gray-400">{step.status}</p>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        <div className="pt-4 text-center">
          <p className="text-sm text-gray-400 italic">شكراً لاختيارك Cute Base Abaya 🤍</p>
        </div>

        {onBack && (
          <button onClick={onBack} className="w-full py-4 text-pink-600 font-bold border border-pink-100 rounded-2xl hover:bg-pink-50 transition-all flex items-center justify-center gap-2">
            <ArrowRight size={18} />
            العودة للوحة الإدارة
          </button>
        )}
      </div>
    </div>
  );
};

export default TrackingView;

import React, { useState, useEffect } from 'react';
import { ViewType, Order, Customer } from './types';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import OrderForm from './components/OrderForm';
import OrderList from './components/OrderList';
import Reports from './components/Reports';
import CustomerList from './components/CustomerList';
import InvoiceView from './components/InvoiceView';
import TrackingView from './components/TrackingView';
import { storage } from './services/storage';
import { Menu } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewType>('dashboard');
  const [selectedOrder, setSelectedOrder] = useState<Order | undefined>(undefined);
  const [printingOrder, setPrintingOrder] = useState<Order | undefined>(undefined);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [trackingOrder, setTrackingOrder] = useState<Order | undefined>(undefined);

  // Check for tracking URL on load
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const trackId = params.get('track');
    if (trackId) {
      const orders = storage.getOrders();
      const order = orders.find(o => o.id === trackId);
      if (order) {
        setTrackingOrder(order);
        setCurrentView('tracking');
      }
    }
  }, []);

  const handleEditOrder = (order: Order) => {
    setSelectedOrder(order);
    setCurrentView('new-order');
  };

  const handleCreateForCustomer = (customer: Customer) => {
    const newId = typeof crypto.randomUUID === 'function' ? crypto.randomUUID() : Date.now().toString();
    const newOrder: Partial<Order> = {
      id: newId,
      orderNo: `INV-${Date.now().toString().slice(-6)}`,
      date: new Date().toISOString().split('T')[0],
      customerName: customer.name,
      customerPhone: customer.phone,
      customerAddress: customer.address,
      measurements: customer.lastMeasurements || {
        sleeveFromNeck: '',
        arms: '',
        bust: '',
        sleeveWidth: '',
        waist: '',
        abayaLength: ''
      },
      totalAmount: 0,
      paidAmount: 0,
      remainingAmount: 0,
      discount: 0,
      shipping: 0,
      status: 'قيد التنفيذ' as any,
      createdAt: Date.now()
    };
    setSelectedOrder(newOrder as Order);
    setCurrentView('new-order');
  };

  if (currentView === 'tracking' && trackingOrder) {
    return <TrackingView order={trackingOrder} onBack={() => {
      // Clear URL params and go back
      window.history.replaceState({}, '', window.location.pathname);
      setTrackingOrder(undefined);
      setCurrentView('dashboard');
    }} />;
  }

  const renderView = () => {
    switch (currentView) {
      case 'dashboard':
        return <Dashboard />;
      case 'new-order':
        return (
          <OrderForm 
            key={selectedOrder?.id || 'new'} // Force remount when order changes
            initialOrder={selectedOrder} 
            onComplete={() => {
              setSelectedOrder(undefined);
              setCurrentView('orders');
            }} 
            onPrint={(order) => setPrintingOrder(order)}
          />
        );
      case 'orders':
        return <OrderList onEdit={handleEditOrder} onPrint={(order) => setPrintingOrder(order)} />;
      case 'customers':
        return <CustomerList onSelectCustomer={handleCreateForCustomer} />;
      case 'reports':
        return <Reports />;
      default:
        return <Dashboard />;
    }
  };

  return (
    <div className="flex min-h-screen bg-gray-50/50">
      <Sidebar 
        currentView={currentView} 
        setView={(view) => {
          if (view === 'new-order' && currentView !== 'new-order') {
            setSelectedOrder(undefined);
          }
          setCurrentView(view);
        }} 
        isOpen={isSidebarOpen} 
        onClose={() => setIsSidebarOpen(false)} 
      />

      <main className="flex-1 p-4 md:p-8 lg:p-12 overflow-y-auto">
        <header className="lg:hidden mb-8 flex items-center justify-between">
           <button 
            onClick={() => setIsSidebarOpen(true)}
            className="p-3 bg-white border border-pink-100 rounded-2xl text-pink-600"
          >
            <Menu size={24} />
          </button>
          <div className="flex flex-col items-center">
            <h1 className="text-lg font-bold text-pink-700 uppercase tracking-widest" style={{ fontFamily: 'serif' }}>CUTE BASE</h1>
            <span className="text-[10px] text-pink-300 -mt-1 tracking-[0.4em] uppercase">ABAYA</span>
          </div>
          <div className="w-10"></div> {/* Spacer */}
        </header>

        <div className="max-w-7xl mx-auto animate-in fade-in slide-in-from-bottom-2 duration-500">
          {renderView()}
        </div>
      </main>

      {printingOrder && (
        <InvoiceView order={printingOrder} onClose={() => setPrintingOrder(undefined)} />
      )}
    </div>
  );
};

export default App;
